sql:
SELECT approval_id, label, status
FROM regulatory_approvals
WHERE status = 'approved';

external_knowledge:
- "Given a green light" refers to approvals with a status of 'approved'; 
- "Under the umbrella of current legislation" means the legislation expiration date is in the future; 
- "Successfully passed their most recent compliance checks" refers to approvals with a latest check status of 'passed'.

sql:
SELECT title, description
FROM legislation
WHERE effective_date = '2023-01-01';
